package main

import "fmt"

type Dog struct { Name string }

// Look at the (d Dog) between func and Bark()
// This attaches the Bark method to the Dog struct!
func (d Dog) Bark() {
    fmt.Println(d.Name, "says WOOF!")
}

func main() {
    fido := Dog{Name: "Fido"}

    // Now we call it using dot notation on the variable!
    fido.Bark()
}
